+        assert_eq!(snapshot_c.position, Position::new(2.0, 3.0));
+        assert_eq!(arena.index_of(c), Some(1));
+
+        let d = arena.insert(sample_agent(3));
+        assert_ne!(
+            b, d,
+            "generational handles should not be reused immediately"
